#[test]
fn test_render_tab_preserves_highlight() {
    use crate::buffer::OptimizedBuffer;

    let mut buffer = TextBuffer::new();
    buffer.set_text("Hello\tWorld");
    buffer.add_highlight(0..11, Style::bold(), 1);

    eprintln!("[TEST] Text: {:?}", buffer.to_string());
    eprintln!("[TEST] Highlight: 0..11 (entire text including tab)");

    let view = TextBufferView::new(&buffer).viewport(0, 0, 40, 1);
    let mut output = OptimizedBuffer::new(40, 1);
    view.render_to(&mut output, 0, 0);

    // Log each cell
    for x in 0..20 {
        if let Some(cell) = output.get(x, 0) {
            let ch = cell.content.grapheme.as_deref().unwrap_or(" ");
            let is_bold = cell.style.attrs.bold;
            eprintln!("[TEST] Cell[{}]: {:?} bold={}", x, ch, is_bold);
        }
    }

    // Verify "Hello" cells (0-4) are bold
    for x in 0..5 {
        let cell = output.get(x, 0).expect("Cell should exist");
        assert!(cell.style.attrs.bold, "Cell {} 'Hello' should be bold", x);
    }

    // Verify tab spaces (cells 5-7 assuming tab_width=4) are also bold
    for x in 5..8 {
        let cell = output.get(x, 0).expect("Tab cell should exist");
        assert!(cell.style.attrs.bold, 
            "Tab cell {} should be bold (preserving highlight), style={:?}", 
            x, cell.style);
    }

    // Verify "World" cells are bold
    for x in 8..13 {
        if let Some(cell) = output.get(x, 0) {
            assert!(cell.style.attrs.bold, "Cell {} 'World' should be bold", x);
        }
    }

    eprintln!("[TEST] PASS: Tab characters preserve highlight style");
}

#[test]
fn test_render_tab_with_selection() {
    use crate::buffer::OptimizedBuffer;

    let mut buffer = TextBuffer::new();
    buffer.set_text("A\tB");

    eprintln!("[TEST] Text: {:?}", buffer.to_string());

    let selection_style = Style::builder().bg(Rgba::from_rgb_u8(60, 60, 120)).build();
    let mut view = TextBufferView::new(&buffer).viewport(0, 0, 20, 1);
    view.set_selection(0, 3, selection_style);  // Select "A\tB"

    let mut output = OptimizedBuffer::new(20, 1);
    view.render_to(&mut output, 0, 0);

    // Log cells
    for x in 0..10 {
        if let Some(cell) = output.get(x, 0) {
            let ch = cell.content.grapheme.as_deref().unwrap_or(" ");
            let has_bg = cell.style.bg.is_some();
            eprintln!("[TEST] Cell[{}]: {:?} has_bg={}", x, ch, has_bg);
        }
    }

    // All selected cells (A, tab spaces, B) should have selection background
    let cell_a = output.get(0, 0).unwrap();
    assert!(cell_a.style.bg.is_some(), "Cell 'A' should have selection bg");

    // Tab cells (1-3 or so) should also have selection bg
    for x in 1..4 {
        if let Some(cell) = output.get(x, 0) {
            assert!(cell.style.bg.is_some(), 
                "Tab cell {} should have selection bg, style={:?}", x, cell.style);
        }
    }

    eprintln!("[TEST] PASS: Tab characters show selection style");
}

#[test]
fn test_render_multiple_highlights_with_tabs() {
    use crate::buffer::OptimizedBuffer;

    let mut buffer = TextBuffer::new();
    buffer.set_text("red\tgreen\tblue");

    // Different highlights for each word
    buffer.add_highlight(0..3, Style::fg(Rgba::RED), 1);      // "red"
    buffer.add_highlight(4..9, Style::fg(Rgba::GREEN), 1);    // "green"  
    buffer.add_highlight(10..14, Style::fg(Rgba::BLUE), 1);   // "blue"

    eprintln!("[TEST] Text with multiple highlights separated by tabs");

