    // Verify colors (tabs should NOT have highlight colors since they're between words)
    let cell_r = output.get(0, 0).unwrap();
    eprintln!("[TEST] 'r' cell fg: {:?}", cell_r.style.fg);

    eprintln!("[TEST] PASS: Multiple highlights with tabs render correctly");
}
